const ALLOWED_USERS = ['6272541552'];
const items = $input.all();
const cb = items[0].json.callback_query;
if (!cb) throw new Error('No callback_query in update');

const fromId = String(cb.from?.id || '');
if (!ALLOWED_USERS.includes(fromId)) {
  throw new Error(`Unauthorized user ${fromId}`);
}

const data = cb.data || '';
const parts = data.split(':');
if (parts.length < 3) throw new Error(`Malformed callback_data: ${data}`);
const [action, jobId, candidateIdxStr] = parts;
const candidateIndex = parseInt(candidateIdxStr, 10);

const chatId = cb.message?.chat?.id;
const messageId = cb.message?.message_id;
const callbackQueryId = cb.id;

return [{
  json: {
    job_id: jobId,
    action,
    candidate_index: candidateIndex,
    chat_id: chatId,
    message_id: messageId,
    callback_query_id: callbackQueryId,
    from_id: fromId,
    ts: new Date().toISOString()
  }
}];

const cb = $('Parse Callback + Authorize').first().json;
const TG_SEND = 'https://api.telegram.org/bot' + $env.TELEGRAM_BOT_TOKEN + '/sendMessage';
async function tgSend(text) {
  try {
    await this.helpers.httpRequest({
      method: 'POST', url: TG_SEND, json: true,
      body: { chat_id: cb.chat_id, text, parse_mode: 'Markdown' },
      timeout: 8000,
    });
  } catch (_) { /* ignore */ }
}

const item = $input.first();
// Missing job file path: readWriteFile returned an empty item (alwaysOutputData
// kept the node flowing). This happens when the candidate cards are older
// than the last /clear, or older than 24h, or have been cancelled+pruned.
if (!item || !item.binary || !item.binary.data) {
  await tgSend(
    'I couldn\'t find job `' + cb.job_id + '` on disk. ' +
    'This usually means the candidate cards were cleared (via /clear) or ' +
    'have expired.\n\nSend `/reel <topic>` to generate fresh cards.'
  );
  return [];
}

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
let job;
try { job = JSON.parse(buf.toString('utf8')); }
catch (e) { throw new Error('Job file for ' + cb.job_id + ' is not valid JSON: ' + e.message); }

if (job.status === 'cancelled') {
  await tgSend(
    'Job `' + cb.job_id + '` was cancelled via /cancel. No reel will be rendered.\n' +
    'Start fresh with /reel <topic>.'
  );
  return [];
}

const candidate = (job.candidates || []).find(c => c.index === cb.candidate_index);
if (!candidate) {
  throw new Error('Candidate index ' + cb.candidate_index + ' not found for job ' + cb.job_id + '. Available: ' + (job.candidates || []).map(c => c.index).join(','));
}

const compositeId = cb.job_id + '_' + candidate.label;
return [{
  json: {
    base_job_id: cb.job_id,
    job_id: compositeId,
    candidate_index: cb.candidate_index,
    candidate_label: candidate.label,
    chat_id: cb.chat_id,
    callback_query_id: cb.callback_query_id,
    source: candidate.source,
    title: candidate.title,
    link: candidate.link,
    content_json: candidate.content_json
  }
}];

// Ensure input has callback_query at top level so Parse Callback + Authorize works unchanged.
return $input.all().map(item => {
  const j = item.json || {};
  if (j.callback_query) return { json: j };
  // If caller passed the callback_query directly, wrap it
  if (j.id && j.from && j.data !== undefined) return { json: { callback_query: j } };
  return { json: j };
});

const stored = $('Load Stored Job').first().json;
const cj = stored.content_json || {};
const beats = cj.beats || [];
if (beats.length === 0) throw new Error('Job has no beats to narrate');
const script = beats.map(b => String(b.text || '').trim()).filter(Boolean).join(' ');
const voice_id = 'nPczCjzI2devNBz1zQrb';
return [{
  json: {
    job_id: stored.job_id,
    chat_id: stored.chat_id,
    title: stored.title,
    source: stored.source,
    link: stored.link,
    content_json: cj,
    tts_script: script,
    tts_char_count: script.length,
    voice_id,
  }
}];

