const job = $('Load Stored Job').first().json;
const base = job.content_json || {};
const narrationResp = $('Bridge: Narration').first().json;
const captionsResp = $('Bridge: Captions').first().json;
const wordTimings = Array.isArray(narrationResp.word_timings) ? narrationResp.word_timings : [];
const beatWindows = Array.isArray(captionsResp.beats) ? captionsResp.beats : [];
const beatWindowById = {};
for (const bw of beatWindows) beatWindowById[bw.id] = bw;


// -------- Fallback scene rotation (variety fix 2026-04-23) --------
// When shape-rescue fires or BrollClip has no image, don't always fall back
// to VersionReveal. Pick an unused scene from a safe pool so duplicates never
// happen silently.
const FALLBACK_POOL = ['BadgeOverlay', 'QuoteCallout', 'StatBlock', 'CommandPills', 'IconGrid', 'DoubleStatHero'];

function pickUnusedFallback(usedSceneSet) {
  for (const s of FALLBACK_POOL) {
    if (!usedSceneSet.has(s)) return s;
  }
  // Everything in the pool already used, last resort.
  return 'BadgeOverlay';
}

function defaultPropsFor(scene, beat, brandCtx, accentFallback) {
  const brand = brandCtx;
  const accent = accentFallback || 'cyan';
  const title = (beat && beat.text) || '';
  const intent = (beat && beat.intent) || '';
  const headline = title.slice(0, 70) || intent.replace(/_/g, ' ') || 'HIGHLIGHT';
  const subhead = title.slice(0, 60);
  switch (scene) {
    case 'BadgeOverlay':
      return { brand, accent, headline, subhead: subhead || intent, badge: { text: 'NEW', accent } };
    case 'QuoteCallout':
      return { brand, accent, quote: title.slice(0, 120) || headline, attribution: (brandCtx || 'The Team').toString().toUpperCase() };
    case 'StatBlock':
      return { brand, accent, headline: intent.replace(/_/g, ' ') || 'THE NUMBERS', stats: [ { label: 'BEATS', value: '8' }, { label: 'SCENE', value: 'ROTATED' } ] };
    case 'CommandPills':
      return { brand, accent, headline: headline || 'KEY MOVES', pills: [ { text: 'STEP 1', accent }, { text: 'STEP 2', accent }, { text: 'STEP 3', accent } ] };
    case 'IconGrid':
      return { brand, accent, headline: headline || 'ECOSYSTEM', items: ['OpenAI','Anthropic','Google','Meta','xAI','Mistral'] };
    case 'DoubleStatHero':
      return { brand, accent, headline: headline, leftStat: { label: 'ONE', value: '1' }, rightStat: { label: 'TWO', value: '2' }, separator: '+' };
    default:
      return { brand, accent, headline, subhead };
  }
}

// -------- Sanitize props so Remotion's Zod schema accepts them --------
const PALETTE = ['coral','cyan','red','green','yellow','orange','purple','pink','blue','white','muted'];
const PALETTE_HEX = {
  coral: [0xef,0x44,0x44], cyan: [0x22,0xd3,0xee], red: [0xef,0x44,0x44],
  green: [0x10,0xa3,0x7f], yellow: [0xfa,0xcc,0x15], orange: [0xf9,0x73,0x16],
  purple: [0xa8,0x55,0xf7], pink: [0xec,0x48,0x99], blue: [0x3b,0x82,0xf6],
  white: [0xff,0xff,0xff], muted: [0x64,0x74,0x8b],
};
function hexToRgb(h) {
  const s = String(h || '').replace('#','').trim();
  if (s.length === 3) return [parseInt(s[0]+s[0],16), parseInt(s[1]+s[1],16), parseInt(s[2]+s[2],16)];
  if (s.length === 6) return [parseInt(s.slice(0,2),16), parseInt(s.slice(2,4),16), parseInt(s.slice(4,6),16)];
  return null;
}
function nearestPalette(hex) {
  const rgb = hexToRgb(hex); if (!rgb) return null;
  let best = 'cyan', bestD = Infinity;
  for (const name of PALETTE) {
    const p = PALETTE_HEX[name];
    const d = (rgb[0]-p[0])**2 + (rgb[1]-p[1])**2 + (rgb[2]-p[2])**2;
    if (d < bestD) { bestD = d; best = name; }
  }
  return best;
}
function coerceAccent(a, fallback) {
  if (!a) return fallback;
  const s = String(a).toLowerCase();
  if (PALETTE.includes(s)) return s;
  if (s.startsWith('#') || /^[0-9a-f]{6}$/i.test(s)) return nearestPalette(s) || fallback;
  return fallback;
}

const BRAND_ACCENT = {
  anthropic: 'coral', openai: 'cyan', gemini: 'cyan', google: 'blue',
  meta: 'blue', xai: 'white', deepseek: 'purple', mistral: 'orange',
  huggingface: 'yellow', github: 'white', generic: 'cyan',
};
const defaultAccent = BRAND_ACCENT[base.brand] || 'cyan';

const SCENE_DEFAULT_SFX = {
  VersionReveal: ['whoosh_long'], MockTweetCard: ['slide_in'],
  CommandPills: ['ui_chime'], BadgeOverlay: ['badge_ping'],
  MockTerminal: ['mech_click'], MockEditor: ['ui_tick'],
  SkillLabel: ['ui_chime'], SkillDone: ['success_ding'],
  ComparisonCards: ['badge_ping'], BrowserReveal: ['click_soft'],
  CounterPain: ['whoosh_long'], ProgressBars: ['progress_complete'],
  SeverityCards: ['badge_ping'], CTAOutro: ['success_fanfare'],
  BrollClip: ['whoosh_long'], BigStatStack: ['badge_ping'],
  HeroQuestion: ['ui_chime'], TimelineConnector: ['slide_in'],
  SplitFactCard: ['slide_in'], UrlRevealCard: ['ui_blip'],
  TabSelectorPillars: ['slide_in'], TestimonialCards: ['slide_in'],
  CommunityQuoteGrid: ['slide_in'],
};

const VALID_SFX = new Set([
  'cold_open_stinger','slidein_badge','mech_click_1','mech_click_2','mech_click',
  'typewriter','soft_tap','click_hard','click_soft','tick','ui_tick','blip','ui_blip',
  'beep','pop','ding','chime','ui_chime','badge_ping','whoosh_short','whoosh_long',
  'swoosh_up','swoosh_down','slide_in','slide_out','card_flip','zoom_in',
  'success_ding','success_fanfare','error_buzz','error_static','fail_thud','alert',
  'confirm_accept','reject_deny','lock','unlock','notification',
  'counter_tick','countdown_beep','progress_complete','compile_done',
]);

// --- Scene shape guard -------------------------------------------------
// Claude occasionally mis-writes complex nested scene props (e.g.
// ComparisonCards.left as a string instead of an object). Rather than
// crash Remotion, we either coerce or swap the beat to VersionReveal.
function rescueBeatShape(beat, beatAccent) {
  const scene = beat.scene;
  const p = { ...(beat.props || {}) };

  function toColumn(raw, accentFallback) {
    // Valid shape: { title, price?, features: string[], accent? }
    if (raw && typeof raw === 'object' && Array.isArray(raw.features)) {
      return {
        title: String(raw.title || 'Option').slice(0, 40),
        price: raw.price ? String(raw.price).slice(0, 20) : undefined,
        features: raw.features.slice(0, 6).map(f => String(f).slice(0, 50)),
        accent: coerceAccent(raw.accent, accentFallback),
      };
    }
    // Got a string, split on commas / plus-signs to fabricate feature bullets.
    if (typeof raw === 'string' && raw.trim()) {
      const items = raw
        .split(/\s*(?:,|\+|, | - |;)\s*/)
        .map(s => s.trim())
        .filter(Boolean)
        .slice(0, 5);
      return {
        title: items[0] ? items[0].slice(0, 30) : 'Option',
        features: items.length > 1 ? items.slice(1) : [raw.slice(0, 60)],
        accent: accentFallback,
      };
    }
    return null;
  }

  switch (scene) {
    case 'ComparisonCards': {
      const c = p.comparison || {};
      const left = toColumn(c.left, beatAccent);
      const right = toColumn(c.right, beatAccent);
      if (!left || !right) return null;  // unrecoverable
      const winner = c.winner === 'left' || c.winner === 'right' ? c.winner : undefined;
      p.comparison = { left, right, winner, winnerLabel: c.winnerLabel ? String(c.winnerLabel).slice(0, 30) : undefined };
      return p;
    }
    case 'CommandPills':
      if (!Array.isArray(p.pills) || p.pills.length === 0) return null;
      p.pills = p.pills.slice(0, 5).map(pill => (
        typeof pill === 'string' ? { text: pill.slice(0, 30), accent: beatAccent } : pill
      ));
      return p;
    case 'ProgressBars':
      if (!Array.isArray(p.bars) || p.bars.length === 0) return null;
      p.bars = p.bars.slice(0, 6).map(b => ({
        label: String(b.label || 'Metric').slice(0, 30),
        accent: coerceAccent(b.accent, beatAccent),
        targetPct: typeof b.targetPct === 'number' ? Math.max(0, Math.min(100, b.targetPct)) : 80,
      }));
      return p;
    case 'MockTerminal':
      if (!Array.isArray(p.logLines) || p.logLines.length === 0) return null;
      p.logLines = p.logLines.slice(0, 8).map(l => ({
        role: String(l.role || 'info').slice(0, 12),
        text: String(l.text || '').slice(0, 80),
      }));
      return p;
    case 'MockEditor':
      if (!Array.isArray(p.lines) || p.lines.length === 0) return null;
      p.lines = p.lines.slice(0, 10).map(l => ({
        text: String(l.text || '').slice(0, 80),
        color: ['key','value','string','muted','accent','number'].includes(l.color) ? l.color : 'value',
        check: Boolean(l.check),
      }));
      return p;
    case 'SeverityCards':
      if (!Array.isArray(p.cards) || p.cards.length === 0) return null;
      p.cards = p.cards.slice(0, 6).map(c => ({
        severity: ['HIGH','MED','LOW'].includes(String(c.severity).toUpperCase()) ? String(c.severity).toUpperCase() : 'MED',
        confidence: typeof c.confidence === 'number' ? c.confidence : 80,
        title: String(c.title || 'Risk').slice(0, 40),
        path: String(c.path || ',').slice(0, 40),
      }));
      return p;
    case 'BigStatStack':
      if (!Array.isArray(p.stats)) {
        // Build from headline if missing.
        if (p.headline || p.subhead) {
          p.stats = [{ label: String(p.headline || 'Stat').slice(0, 20), value: String(p.subhead || '').slice(0, 20) }];
        } else return null;
      }
      p.stats = p.stats.slice(0, 4).map(s => ({
        label: String(s.label || 'Metric').slice(0, 20),
        value: String(s.value || '').slice(0, 20),
      }));
      return p;
    case 'TimelineConnector':
      if (!Array.isArray(p.events) || p.events.length === 0) return null;
      p.events = p.events.slice(0, 6).map(e => ({
        label: String(e.label || 'Event').slice(0, 30),
        date: String(e.date || '').slice(0, 16),
      }));
      return p;
    case 'TestimonialCards':
      if (!Array.isArray(p.testimonials) || p.testimonials.length === 0) return null;
      p.testimonials = p.testimonials.slice(0, 4).map(t => ({
        quote: String(t.quote || '').slice(0, 140),
        attribution: String(t.attribution || 'User').slice(0, 40),
      }));
      return p;
    case 'CommunityQuoteGrid':
      if (!Array.isArray(p.quotes) || p.quotes.length === 0) return null;
      p.quotes = p.quotes.slice(0, 8).map(q => ({
        text: String(q.text || q.quote || '').slice(0, 80),
        attribution: String(q.attribution || '').slice(0, 30),
      }));
      return p;
    case 'TabSelectorPillars':
      if (!Array.isArray(p.tabs) || p.tabs.length === 0) return null;
      p.tabs = p.tabs.slice(0, 4).map(t => ({
        label: String(t.label || 'Tab').slice(0, 20),
        items: Array.isArray(t.items) ? t.items.slice(0, 6).map(x => String(x).slice(0, 60)) : [],
      }));
      return p;
    case 'CounterPain':
      if (!p.counter || typeof p.counter !== 'object') return null;
      p.counter = {
        label: String(p.counter.label || 'Count').slice(0, 30),
        from: typeof p.counter.from === 'number' ? p.counter.from : 0,
        to: typeof p.counter.to === 'number' ? p.counter.to : 100,
        durationSec: typeof p.counter.durationSec === 'number' ? p.counter.durationSec : 3,
      };
      return p;
    case 'QuoteCallout':
      if (!p.quote || typeof p.quote !== 'string' || p.quote.length < 3) return null;
      p.quote = p.quote.slice(0, 180);
      if (p.attribution) p.attribution = String(p.attribution).slice(0, 60);
      if (p.kicker) p.kicker = String(p.kicker).slice(0, 40);
      return p;
    case 'StatBlock':
      if (!Array.isArray(p.stats) || p.stats.length === 0) return null;
      p.stats = p.stats.slice(0, 4).map(s => ({
        label: String(s.label || 'Metric').slice(0, 24),
        value: String(s.value || '').slice(0, 16),
      }));
      return p;
    case 'MapMoment':
      // headline required; pins/stat optional.
      if (!p.headline && !p.stat) return null;
      if (Array.isArray(p.pins)) p.pins = p.pins.slice(0, 8).map(s => String(s).slice(0, 20));
      if (p.stat) p.stat = String(p.stat).slice(0, 20);
      return p;
    case 'PricingReveal':
      if (!p.price) return null;
      p.price = String(p.price).slice(0, 20);
      p.unit = String(p.unit || '/mo').slice(0, 16);
      if (p.tier) p.tier = String(p.tier).slice(0, 14);
      if (Array.isArray(p.features)) p.features = p.features.slice(0, 6).map(f => String(f).slice(0, 50));
      else p.features = [];
      return p;
    case 'VsTimeline':
      if (!Array.isArray(p.markers) || p.markers.length < 2) return null;
      p.markers = p.markers.slice(0, 5).map(m => ({
        label: String(m.label || 'Event').slice(0, 24),
        date: String(m.date || '').slice(0, 10),
        highlight: Boolean(m.highlight),
      }));
      return p;
    case 'IconGrid':
      if (!Array.isArray(p.items) || p.items.length < 3) return null;
      p.items = p.items.slice(0, 8).map(s => String(s).slice(0, 20));
      return p;
    case 'DoubleStatHero':
      if (!p.leftStat || !p.rightStat) return null;
      p.leftStat = {
        label: String(p.leftStat.label || 'Metric').slice(0, 24),
        value: String(p.leftStat.value || '').slice(0, 12),
      };
      p.rightStat = {
        label: String(p.rightStat.label || 'Metric').slice(0, 24),
        value: String(p.rightStat.value || '').slice(0, 12),
      };
      if (p.separator) p.separator = String(p.separator).slice(0, 4);
      return p;
    case 'CodeInline':
      // Accept code as string or array; normalize to array.
      if (!p.code) return null;
      const codeArr = Array.isArray(p.code) ? p.code : [p.code];
      p.code = codeArr.slice(0, 4).map(l => String(l).slice(0, 80));
      if (p.code.length === 0) return null;
      if (p.caption) p.caption = String(p.caption).slice(0, 120);
      if (p.language) p.language = String(p.language).slice(0, 10);
      return p;
    case 'HeroQuestion':
      if (!p.headline || typeof p.headline !== 'string' || p.headline.length < 5) return null;
      p.headline = p.headline.slice(0, 140);
      return p;
    default:
      return p;  // scenes without complex shape; pass through
  }
}

function sanitizeProps(scene, p) {
  const out = { ...(p || {}) };
  out.brand = out.brand || base.brand || 'generic';
  out.accent = coerceAccent(out.accent, defaultAccent);
  if (out.accent2) out.accent2 = coerceAccent(out.accent2, undefined);
  if (Array.isArray(out.pills)) {
    out.pills = out.pills.map(pill => ({ ...pill, accent: coerceAccent(pill.accent, defaultAccent) }));
  }
  if (Array.isArray(out.bars)) {
    out.bars = out.bars.map(b => ({ ...b, accent: coerceAccent(b.accent, defaultAccent) }));
  }
  if (out.badge) out.badge = { ...out.badge, accent: coerceAccent(out.badge.accent, defaultAccent) };
  if (Array.isArray(out.cards)) {
    out.cards = out.cards.map(c => {
      const sev = String(c.severity || 'MED').toUpperCase();
      return { ...c, severity: ['HIGH','MED','LOW'].includes(sev) ? sev : 'MED' };
    });
  }
  if (scene === 'CTAOutro') out.outroStyle = 'follow';
  return out;
}

function sanitizeSfxHints(scene, hints) {
  const seen = new Set();
  const kept = [];
  for (const h of (hints || [])) {
    if (typeof h !== 'string') continue;
    if (!VALID_SFX.has(h)) continue;
    if (seen.has(h)) continue;
    seen.add(h);
    kept.push(h);
  }
  if (kept.length === 0) {
    const def = SCENE_DEFAULT_SFX[scene] || [];
    def.forEach(h => { if (!seen.has(h)) { kept.push(h); seen.add(h); } });
  }
  return kept.slice(0, 2);
}

// -------- Pill / item highlight timing computation --------
const FILLER = new Set(['the','a','an','of','for','and','or','to','in','on','with','by','is','are','be','its','that','this','these','those','use','uses','using']);
function tokenize(s) {
  return String(s || '').toLowerCase().replace(/[^a-z0-9\s]+/g, ' ').split(/\s+/).filter(t => t.length >= 2 && !FILLER.has(t));
}
function normalizeWord(s) {
  return String(s || '').toLowerCase().replace(/[^a-z0-9]+/g, '');
}
function findPhraseInWords(words, phraseTokens) {
  if (phraseTokens.length === 0) return null;
  const first = phraseTokens[0];
  for (let i = 0; i < words.length; i++) {
    if (normalizeWord(words[i].text) === first) {
      const window = words.slice(i, i + phraseTokens.length + 3);
      const windowNormalized = window.map(w => normalizeWord(w.text));
      let pos = 0;
      let lastIdx = 0;
      for (let t = 0; t < phraseTokens.length; t++) {
        const tok = phraseTokens[t];
        while (pos < windowNormalized.length && windowNormalized[pos] !== tok) pos++;
        if (pos >= windowNormalized.length) break;
        lastIdx = pos;
        pos += 1;
      }
      if (pos <= windowNormalized.length) {
        const s = window[0].start;
        const e = window[Math.min(lastIdx, window.length - 1)].end;
        return { startSec: s, endSec: e };
      }
    }
  }
  return null;
}
function computePillHighlights(pills, beatWindow) {
  if (!pills || pills.length === 0 || !beatWindow) return pills;
  const { startSec, endSec } = beatWindow;
  const beatWords = wordTimings.filter(w => w.start >= startSec && w.end <= endSec + 0.1);
  const beatDur = Math.max(0.1, endSec - startSec);
  const slotDur = beatDur / pills.length;
  return pills.map((pill, idx) => {
    const tokens = tokenize(pill.text);
    let hit = findPhraseInWords(beatWords, tokens);
    if (!hit) {
      const fallbackStart = startSec + idx * slotDur;
      hit = { startSec: fallbackStart, endSec: fallbackStart + Math.min(slotDur, 2.0) };
    }
    const rawDur = hit.endSec - hit.startSec;
    const durSec = Math.max(0.8, Math.min(rawDur + 0.6, 2.2));
    return {
      ...pill,
      highlightAtSec: Math.max(0, hit.startSec - startSec),
      highlightDurSec: durSec,
    };
  });
}

// Collect already-used scene types so fallbacks can pick unused ones.
const usedScenes = new Set((base.beats || []).map(b => b.scene).filter(Boolean));

let sanitizedBeats = (base.beats || []).map(b => {
  let cleanedProps = sanitizeProps(b.scene, b.props);
  // Run shape rescue; if the scene is unrecoverable, swap to VersionReveal.
  const rescued = rescueBeatShape({ scene: b.scene, props: cleanedProps }, cleanedProps.accent);
  let scene = b.scene;
  if (rescued === null) {
    // Shape unrescuable. Swap to an unused fallback scene (not always VersionReveal).
    scene = pickUnusedFallback(usedScenes);
    cleanedProps = defaultPropsFor(scene, b, cleanedProps.brand, cleanedProps.accent);
    usedScenes.add(scene);
  } else {
    cleanedProps = rescued;
  }
  if (scene === 'CommandPills' && Array.isArray(cleanedProps.pills)) {
    const bw = beatWindowById[b.id];
    cleanedProps.pills = computePillHighlights(cleanedProps.pills, bw);
  }
  return {
    ...b,
    scene,
    props: cleanedProps,
    sfxHints: sanitizeSfxHints(scene, b.sfxHints),
  };
});

// -------- Fetch og:image (best-effort) --------
let brollSrc = null;
try {
  const brollResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://host.docker.internal:5555/broll',
    json: true,
    body: { job_id: job.job_id, url: job.link },
    timeout: 20000,
  });
  if (brollResp && brollResp.ok) brollSrc = brollResp.broll_src;
} catch (e) { /* continue without broll */ }

// First, find any BrollClip beats Claude picked. Enforce max 1.
const brollIndices = sanitizedBeats
  .map((b, i) => (b.scene === 'BrollClip' ? i : -1))
  .filter(i => i >= 0);

if (brollIndices.length > 0) {
  // Keep the first BrollClip; inject broll_src if we have it; swap the rest to VersionReveal.
  const keepIdx = brollIndices[0];
  if (brollSrc) {
    const beat = sanitizedBeats[keepIdx];
    sanitizedBeats[keepIdx] = {
      ...beat,
      props: {
        brand: beat.props.brand,
        accent: beat.props.accent,
        brollSrc,
        title: beat.props.title || job.title,
        sourceBadge: beat.props.sourceBadge || (job.source || 'AI NEWS').toUpperCase().replace('-', ' '),
      },
    };
  } else {
    // No image fetched; rotate to an unused fallback instead of forcing VersionReveal.
    const beat = sanitizedBeats[keepIdx];
    const usedNow = new Set(sanitizedBeats.map(x => x.scene).filter(Boolean));
    usedNow.delete('BrollClip'); // we're replacing this slot
    const newScene = pickUnusedFallback(usedNow);
    sanitizedBeats[keepIdx] = {
      ...beat,
      scene: newScene,
      props: defaultPropsFor(newScene, beat, beat.props.brand, beat.props.accent),
    };
  }
  // Rotate every extra BrollClip to an unused fallback scene.
  for (const i of brollIndices.slice(1)) {
    const beat = sanitizedBeats[i];
    const usedNow = new Set(sanitizedBeats.map((x, j) => j === i ? null : x.scene).filter(Boolean));
    const newScene = pickUnusedFallback(usedNow);
    sanitizedBeats[i] = {
      ...beat,
      scene: newScene,
      props: defaultPropsFor(newScene, beat, beat.props.brand, beat.props.accent),
    };
  }
} else if (brollSrc && sanitizedBeats.length >= 4) {
  // No BrollClip from Claude, but we have an image, inject one at the middle.
  const HEAVY_UI = new Set(['MockTerminal','MockEditor','ComparisonCards','CTAOutro','VersionReveal']);
  const eligible = sanitizedBeats
    .map((b, i) => ({ b, i }))
    .filter(({ b, i }) => i > 0 && i < sanitizedBeats.length - 1 && !HEAVY_UI.has(b.scene));
  if (eligible.length > 0) {
    const mid = Math.floor(sanitizedBeats.length / 2);
    eligible.sort((a, z) => Math.abs(a.i - mid) - Math.abs(z.i - mid));
    const target = eligible[0];
    const originalBeat = sanitizedBeats[target.i];
    sanitizedBeats[target.i] = {
      ...originalBeat,
      scene: 'BrollClip',
      props: {
        brand: originalBeat.props.brand,
        accent: originalBeat.props.accent,
        brollSrc,
        title: job.title,
        sourceBadge: (job.source || 'AI NEWS').toUpperCase().replace('-', ' '),
      },
    };
  }
}

const final_content_json = {
  ...base,
  id: job.job_id,
  brand: base.brand || 'generic',
  audioSrc: 'narration-' + job.job_id + '.mp3',
  captionsSrc: 'captions-' + job.job_id + '.json',
  beats: sanitizedBeats,
  captionsMode: 'always',
  channelLabel: 'AI Reel Generator',
  captionWordEffect: 'magnify',
};

return [{
  json: {
    job_id: job.job_id,
    chat_id: job.chat_id,
    title: job.title,
    source: job.source,
    broll_src: brollSrc,
    final_content_json,
  }
}];

